class Solution {
public:
    bool digitCount(string num) {
        for (int i = 0; i < num.size(); i++) {
            int digit = num[i] - '0';
            if (count(num.begin(), num.end(), digit) != i + 1) {
                return false;
            }
        }
        return true;
    }
};
```
